-- Rohit bracket seed (champion Spain). Run after migration_bracket.sql.
-- group_position_picks
on conflict (league_id,user_id,group_letter,predicted_position) do update set team_id=excluded.team_id;

-- third_slot_picks (Annexe C routed)
on conflict (league_id,user_id,slot_match_id) do update set team_id=excluded.team_id;

-- bracket_picks (advancers)
on conflict (league_id,user_id,match_id) do update set advancing_team_id=excluded.advancing_team_id;

-- champion
on conflict (league_id,user_id) do update set team_id=excluded.team_id;
